    const db = new Dirty(dbPath);

    db.on('load', () => {
      const largeValue = 'x'.repeat(65536);
      const numKeys = 30;
      let callbackCount = 0;

      db.once('drain', () => {
        // Original: drain fires after all writes complete (queue empty, inFlightWrites=0)
        // Mutated: drain fires while queue still has items → callbacks not all fired yet
        expect(callbackCount).toBe(numKeys);
        db.close();
        db.once('write_close', () => {
          fs.unlink(dbPath, () => done());
        });
      });

      for (let i = 0; i < numKeys; i++) {
        db.set(`key${i}`, { data: largeValue }, () => {
          callbackCount++;
        });
      }
    });

    db.on('error', (err: Error) => {
      fs.unlink(dbPath, () => {});
      done(err);
